import React, { useState, useEffect } from 'react';
import { Link, NavLink } from 'react-router-dom';
import { useTheme } from '../context/ThemeContext';
import './Navbar.css';

const LOGO = 'https://framerusercontent.com/images/4BswMdHtgQYzS7VfAYdYLREayEU.svg';

export default function Navbar() {
  const { isDark, toggleTheme } = useTheme();
  const [scrolled, setScrolled] = useState(false);
  const [menuOpen, setMenuOpen] = useState(false);
  const [bannerDismissed, setBannerDismissed] = useState(false);

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 30);
    window.addEventListener('scroll', onScroll);
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  return (
    <>
      {/* Dark Version Banner */}
      {!bannerDismissed && (
        <div className={`theme-banner ${isDark ? 'banner-dark' : 'banner-light'}`}>
          <span>
            {isDark
              ? '( Currently: Dark version )'
              : '( Currently: Light version )'}
          </span>
          <button
            className="banner-toggle"
            onClick={toggleTheme}
          >
            Switch to {isDark ? 'Light' : 'Dark'} version →
          </button>
          <button className="banner-close" onClick={() => setBannerDismissed(true)}>✕</button>
        </div>
      )}

      <nav className={`navbar ${scrolled ? 'scrolled' : ''}`}>
        <div className="nav-inner container">
          {/* Logo */}
          <Link to="/" className="nav-logo">
            <img
              src={LOGO}
              alt="Scarlet"
              className={isDark ? 'logo-invert' : ''}
            />
          </Link>

          {/* Desktop Links */}
          <ul className="nav-links">
            <li><NavLink to="/about" className={({ isActive }) => isActive ? 'active' : ''}>Studio</NavLink></li>
            <li><NavLink to="/projects" className={({ isActive }) => isActive ? 'active' : ''}>Projects</NavLink></li>
            <li><NavLink to="/blog" className={({ isActive }) => isActive ? 'active' : ''}>Blog</NavLink></li>
          </ul>

          {/* Right side */}
          <div className="nav-right">
            <button
              className="theme-toggle-btn"
              onClick={toggleTheme}
              aria-label="Toggle theme"
              title={isDark ? 'Switch to Light' : 'Switch to Dark'}
            >
              {isDark ? (
                <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><circle cx="12" cy="12" r="5"/><line x1="12" y1="1" x2="12" y2="3"/><line x1="12" y1="21" x2="12" y2="23"/><line x1="4.22" y1="4.22" x2="5.64" y2="5.64"/><line x1="18.36" y1="18.36" x2="19.78" y2="19.78"/><line x1="1" y1="12" x2="3" y2="12"/><line x1="21" y1="12" x2="23" y2="12"/><line x1="4.22" y1="19.78" x2="5.64" y2="18.36"/><line x1="18.36" y1="5.64" x2="19.78" y2="4.22"/></svg>
              ) : (
                <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M21 12.79A9 9 0 1 1 11.21 3 7 7 0 0 0 21 12.79z"/></svg>
              )}
            </button>
            <Link to="/contact" className="nav-cta">Contact us</Link>
            {/* Hamburger */}
            <button
              className={`hamburger ${menuOpen ? 'open' : ''}`}
              onClick={() => setMenuOpen(!menuOpen)}
              aria-label="Menu"
            >
              <span /><span /><span />
            </button>
          </div>
        </div>

        {/* Mobile Menu */}
        <div className={`mobile-menu ${menuOpen ? 'open' : ''}`}>
          <ul>
            <li><NavLink to="/about" onClick={() => setMenuOpen(false)}>Studio</NavLink></li>
            <li><NavLink to="/projects" onClick={() => setMenuOpen(false)}>Projects</NavLink></li>
            <li><NavLink to="/blog" onClick={() => setMenuOpen(false)}>Blog</NavLink></li>
            <li><NavLink to="/contact" onClick={() => setMenuOpen(false)}>Contact us</NavLink></li>
          </ul>
        </div>
      </nav>
    </>
  );
}
